function autoDismissPopup(selector,delay){const el=document.querySelector(selector);if(!el)return;setTimeout(function(){el.classList.add('fade-out');setTimeout(function(){el.remove()},500)},delay||3000)}document.addEventListener('DOMContentLoaded',function(){const menuBtn=document.getElementById('menu_btn');const closeMenuBtn=document.getElementById('close_menu');const mobileNav=document.querySelector('.header_nav_mobile');if(menuBtn&&closeMenuBtn&&mobileNav){menuBtn.addEventListener('click',function(){mobileNav.classList.add('open')});closeMenuBtn.addEventListener('click',function(){mobileNav.classList.remove('open')})}const triggers=document.querySelectorAll('[data-lang-dropdown]');triggers.forEach(function(trigger){trigger.addEventListener('click',function(e){e.stopPropagation();const dropdown=trigger.closest('.lang_dropdown');const isOpen=dropdown.classList.contains('open');document.querySelectorAll('.lang_dropdown.open').forEach(function(d){d.classList.remove('open')});if(!isOpen){dropdown.classList.add('open')}})});const userTriggers=document.querySelectorAll('[data-user-dropdown]');userTriggers.forEach(function(trigger){trigger.addEventListener('click',function(e){e.stopPropagation();const dropdown=trigger.closest('.user_dropdown');const menu=dropdown.querySelector('.user_dropdown_menu');const isOpen=dropdown.classList.contains('open');document.querySelectorAll('.user_dropdown.open').forEach(function(d){d.classList.remove('open');d.querySelector('[data-user-dropdown]').setAttribute('aria-expanded','false')});if(!isOpen){dropdown.classList.add('open');trigger.setAttribute('aria-expanded','true');var firstItem=menu.querySelector('[role="menuitem"]');if(firstItem)firstItem.focus()}})});document.addEventListener('click',function(){document.querySelectorAll('.lang_dropdown.open').forEach(function(d){d.classList.remove('open')});document.querySelectorAll('.user_dropdown.open').forEach(function(d){d.classList.remove('open');var btn=d.querySelector('[data-user-dropdown]');if(btn)btn.setAttribute('aria-expanded','false')})});document.addEventListener('keydown',function(e){if(e.key==='Escape'){document.querySelectorAll('.user_dropdown.open').forEach(function(d){d.classList.remove('open');var btn=d.querySelector('[data-user-dropdown]');if(btn){btn.setAttribute('aria-expanded','false');btn.focus()}})}var openMenu=document.querySelector('.user_dropdown.open.user_dropdown_menu');if(!openMenu)return;var items=Array.from(openMenu.querySelectorAll('[role="menuitem"]'));if(items.length===0)return;var currentIndex=items.indexOf(document.activeElement);if(e.key==='ArrowDown'){e.preventDefault();var nextIndex=(currentIndex+1)%items.length;items[nextIndex].focus()}else if(e.key==='ArrowUp'){e.preventDefault();var prevIndex=(currentIndex-1+items.length)%items.length;items[prevIndex].focus()}});autoDismissPopup('.notification')});(function(){"use strict";function createPlaceholder(img){if(img.hasAttribute("data-fallback"))return;img.setAttribute("data-fallback","1");var alt=img.getAttribute("alt")||"";var outer=document.createElement("div");outer.className="img-placeholder";outer.setAttribute("role","img");outer.setAttribute("aria-label",alt);var card=document.createElement("div");card.className="img-placeholder-card";var iconWrap=document.createElement("div");iconWrap.className="img-placeholder-icon";var icon=document.createElement("i");icon.className="fa-solid fa-image";icon.setAttribute("aria-hidden","true");var title=document.createElement("span");title.className="img-placeholder-title";title.textContent="Image Unavailable";var desc=document.createElement("span");desc.className="img-placeholder-desc";desc.textContent="This image is currently unavailable.";var hint=document.createElement("span");hint.className="img-placeholder-hint";hint.textContent="Please check again later.";iconWrap.appendChild(icon);card.appendChild(iconWrap);card.appendChild(title);card.appendChild(desc);card.appendChild(hint);outer.appendChild(card);var parent=img.parentNode;if(parent)parent.replaceChild(outer,img)}document.addEventListener("DOMContentLoaded",function(){var imgs=document.querySelectorAll("img");for(var i=0;i<imgs.length;i++){if(imgs[i].complete&&imgs[i].naturalWidth===0){createPlaceholder(imgs[i])}}});window.addEventListener("error",function(e){if(e.target instanceof HTMLImageElement){createPlaceholder(e.target)}},true)})();function showNotification(message,type){const icons={success:'fa-check-circle',error:'fa-exclamation-circle',warning:'fa-triangle-exclamation',info:'fa-info-circle'};const el=document.createElement('div');el.className='notification '+type;const icon=document.createElement('i');icon.className='fa-solid '+(icons[type]||icons.info);icon.setAttribute('aria-hidden','true');el.appendChild(icon);el.appendChild(document.createTextNode(' '+message));document.body.appendChild(el);autoDismissPopup('.notification')}document.addEventListener('DOMContentLoaded',function(){const overlay=document.getElementById('authOverlay');const closeBtn=document.getElementById('authClose');const tabs=document.querySelectorAll('.auth_tab');const loginForm=document.getElementById('authLoginForm');const registerForm=document.getElementById('authRegisterForm');var lastFocusedElement=null;document.querySelectorAll('[data-auth-toggle]').forEach(function(el){el.addEventListener('click',function(e){e.preventDefault();lastFocusedElement=document.activeElement;overlay.classList.add('open');document.body.style.overflow='hidden';closeBtn.focus()})});function closeModal(){overlay.classList.remove('open');document.body.style.overflow='';if(lastFocusedElement){lastFocusedElement.focus();lastFocusedElement=null}}closeBtn.addEventListener('click',closeModal);overlay.addEventListener('click',function(e){if(e.target===overlay)closeModal()});document.addEventListener('keydown',function(e){if(e.key==='Escape'&&overlay.classList.contains('open'))closeModal()});tabs.forEach(function(tab){tab.addEventListener('click',function(){tabs.forEach(function(t){t.classList.remove('active');t.setAttribute('aria-selected','false')});tab.classList.add('active');tab.setAttribute('aria-selected','true');const target=tab.getAttribute('data-tab');loginForm.classList.toggle('active',target==='login');registerForm.classList.toggle('active',target==='register')})});function submitForm(form,btn){const formData=new FormData(form);const redirectUrl=window.location.pathname+window.location.search+window.location.hash;formData.set('redirect_url',redirectUrl);btn.classList.add('loading');btn.disabled=true;fetch('../includes/ajax_auth.php',{method:'POST',body:formData}).then(function(res){return res.json()}).then(function(data){btn.classList.remove('loading');btn.disabled=false;if(data.success){if(data.redirect){window.location.href=data.redirect}else{showNotification(data.message||'Account created.Please sign in.','success');document.querySelector('[data-tab="login"]').click();registerForm.reset()}}else{showNotification(data.error||'An error occurred.','error')}}).catch(function(){btn.classList.remove('loading');btn.disabled=false;var overlay=document.getElementById('authOverlay');var errMsg=overlay?overlay.getAttribute('data-unexpected-error'):'';showNotification(errMsg||'An unexpected error occurred.Please try again.','error')})}loginForm.addEventListener('submit',function(e){e.preventDefault();submitForm(loginForm,document.getElementById('authLoginBtn'))});registerForm.addEventListener('submit',function(e){e.preventDefault();submitForm(registerForm,document.getElementById('authRegisterBtn'))})});document.addEventListener('DOMContentLoaded',function(){const items=document.querySelectorAll('.faq_item');items.forEach(function(item){const btn=item.querySelector('.faq_question');btn.addEventListener('click',function(){const isOpen=item.classList.contains('open');items.forEach(function(el){el.classList.remove('open')});if(!isOpen){item.classList.add('open')}})});autoDismissPopup('.notification')});